        .filter((id) => Number.isInteger(id) && id > 0)
    )
  )
    .sort((a, b) => a - b) as number[];
}

function sameIdList(a: number[], b: number[]): boolean {
  if (a.length !== b.length) return false;
  for (let i = 0; i < a.length; i += 1) {
    if (a[i] !== b[i]) return false;
  }
  return true;
}

